    String getCellName(int row, int cell){
        String cellName = "";
        int asciiCode = 65;     //A
        row = row + 1;
        if(cell<26){
            cellName = ""+(char)(asciiCode+cell)+row+"";
        } else {                            
            cellName = "A"+ (char)(asciiCode+(cell-26))+row+"";
        }
        return cellName;
    }
    
    String getWeekFromTo(int year, int mon, int week){
        String weekFromTo = "";
        Calendar c = new GregorianCalendar();
        c.set(Calendar.YEAR, year);
        c.set(Calendar.MONTH, mon);
        c.set(Calendar.WEEK_OF_MONTH, week);
        int dayOfWeek = c.get(Calendar.DAY_OF_WEEK); 
        Calendar calFirstDayInThisWeek = (Calendar)c.clone();
        calFirstDayInThisWeek.add(Calendar.DATE, c.getActualMinimum(Calendar.DAY_OF_WEEK)-dayOfWeek);
        Calendar calLastDayInThisWeek = (Calendar)c.clone();
        calLastDayInThisWeek.add(Calendar.DATE,c.getActualMaximum(Calendar.DAY_OF_WEEK)-dayOfWeek);
        weekFromTo = 
                 (calFirstDayInThisWeek.getTime().getYear()+1900)+"."+
                 (calFirstDayInThisWeek.getTime().getMonth()+1)+"."+
                 calFirstDayInThisWeek.getTime().getDate()+"~"+
                 (calLastDayInThisWeek.getTime().getYear()+1900)+"."+
                 (calLastDayInThisWeek.getTime().getMonth()+1)+"."+
                 calLastDayInThisWeek.getTime().getDate();
        return weekFromTo;
    }

